module gray_code_counter(CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

reg [3:0] gray_counter;

always @(posedge CLK or posedge RST) begin
    if (RST)
        gray_counter <= 4'b0000;
    else
        gray_counter <= gray_counter + 1'b1;
end

always @(gray_counter) begin
    Q = gray_counter ^ (gray_counter >> 1);
end

endmodule
